import React, { useState, useEffect, useMemo } from 'react';

const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#111111',
    surfaceAlt: '#1a1a1a',
    border: '#2a2a2a',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    blue: '#38bdf8',
    yellow: '#fbbf24',
    pink: '#f472b6',
    green: '#a3e635',
    orange: '#fb923c',
    red: '#f43f5e',
  },
  font: "'JetBrains Mono', monospace",
};

const GRADIENTS = [
  { label: 'g1', value: 3e-8, color: theme.colors.blue },
  { label: 'g2', value: -5e-5, color: theme.colors.yellow },
  { label: 'g3', value: 0.5, color: theme.colors.pink },
  { label: 'g4', value: -45.0, color: theme.colors.orange },
];

const FP16_MIN_SUB = 5.96e-8;
const FP16_MIN_NORM = 6.1e-5;
const FP16_MAX = 65504;

function simulateFP16(value) {
  if (value === 0) return { val: 0, status: 'ok' };
  const abs = Math.abs(value);
  const sign = Math.sign(value);
  if (abs > FP16_MAX) return { val: sign * Infinity, status: 'overflow' };
  if (abs < FP16_MIN_SUB) return { val: 0, status: 'underflow' };
  if (abs < FP16_MIN_NORM) {
    const scale = Math.pow(2, -14);
    const m = abs / scale;
    const qm = Math.round(m * 1024) / 1024;
    return { val: sign * qm * scale, status: 'subnormal' };
  }
  const e = Math.floor(Math.log2(abs));
  const m = abs / Math.pow(2, e);
  const qm = (Math.round((m - 1) * 1024) / 1024 + 1);
  return { val: sign * qm * Math.pow(2, e), status: 'ok' };
}

function formatNum(v, forceSign) {
  if (!isFinite(v)) return v > 0 ? '+Inf' : '-Inf';
  const abs = Math.abs(v);
  const s = v < 0 ? '-' : (forceSign ? '+' : '');
  if (v === 0) return '0';
  if (abs >= 1000) return s + abs.toFixed(0);
  if (abs >= 1) return s + abs.toFixed(2);
  if (abs >= 0.001) return s + abs.toFixed(4);
  return s + abs.toExponential(1);
}

const SCALE_STOPS = [1, 2, 4, 8, 16, 32, 64, 128, 256, 512, 1024, 2048, 4096, 8192, 16384, 32768, 65536];

export default function App() {
  const [scaleIdx, setScaleIdx] = useState(10);
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);
  const [hovered, setHovered] = useState(null);

  const lossScale = SCALE_STOPS[scaleIdx];
  const numSteps = 4;

  const pipeline = useMemo(() => {
    return GRADIENTS.map((g) => {
      const original = g.value;
      const scaled = original * lossScale;
      const fp16 = simulateFP16(scaled);
      const hasOverflow = fp16.status === 'overflow' || fp16.status === 'underflow';
      const unscaled = hasOverflow ? 0 : fp16.val / lossScale;
      const finalStatus = fp16.status === 'overflow' ? 'overflow' : fp16.status === 'underflow' ? 'underflow' : (fp16.status === 'subnormal' ? 'imprecise' : 'ok');
      return { ...g, original, scaled, fp16Val: fp16.val, fp16Status: fp16.status, unscaled, finalStatus };
    });
  }, [lossScale]);

  const noScalePipeline = useMemo(() => {
    return GRADIENTS.map((g) => {
      const fp16 = simulateFP16(g.value);
      return fp16.status;
    });
  }, []);

  useEffect(() => {
    if (!playing) return;
    const timer = setTimeout(() => {
      if (step < numSteps - 1) setStep(s => s + 1);
      else { setPlaying(false); }
    }, 1800);
    return () => clearTimeout(timer);
  }, [playing, step]);

  const play = () => { setStep(0); setPlaying(true); };
  const reset = () => { setStep(0); setPlaying(false); setScaleIdx(10); setHovered(null); };

  const SVG_W = 560;
  const SVG_H = 140;
  const PAD_L = 10;
  const PAD_R = 10;
  const LINE_Y = 70;
  const CHART_W = SVG_W - PAD_L - PAD_R;

  const LOG_MIN = -9;
  const LOG_MAX = 6;
  const toX = (logVal) => PAD_L + ((logVal - LOG_MIN) / (LOG_MAX - LOG_MIN)) * CHART_W;

  const zoneUnderX = toX(Math.log10(FP16_MIN_SUB));
  const zoneSubX = toX(Math.log10(FP16_MIN_NORM));
  const zoneOverX = toX(Math.log10(FP16_MAX));

  const stepLabels = ['Original (fp32)', 'Scaled (x' + lossScale + ')', 'fp16 Storage', 'Result (fp32)'];
  const stepColors = [theme.colors.blue, theme.colors.yellow, theme.colors.pink, theme.colors.green];

  const statusColor = (s) => s === 'overflow' || s === 'underflow' ? theme.colors.red : s === 'imprecise' || s === 'subnormal' ? theme.colors.yellow : theme.colors.green;
  const statusLabel = (s) => s === 'overflow' ? 'OVERFLOW' : s === 'underflow' ? 'UNDERFLOW' : s === 'imprecise' || s === 'subnormal' ? 'Low precision' : 'OK';

  const savedCount = pipeline.filter(p => p.finalStatus === 'ok').length;
  const lostCount = pipeline.filter(p => p.finalStatus === 'overflow' || p.finalStatus === 'underflow').length;
  const noScaleLost = noScalePipeline.filter(s => s === 'overflow' || s === 'underflow').length;

  return (
    <div style={{ background: theme.colors.background, minHeight: '100vh', fontFamily: theme.font, color: theme.colors.text, display: 'flex', flexDirection: 'column', alignItems: 'center', padding: '16px 12px' }}>
      <div style={{ maxWidth: 600, width: '100%' }}>
        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 12 }}>
          <div>
            <div style={{ fontSize: 17, fontWeight: 700 }}>Mixed Precision Training</div>
            <div style={{ fontSize: 11, color: theme.colors.textSecondary, marginTop: 2 }}>Adjust loss scale to keep gradients in fp16 safe zone</div>
          </div>
          <div style={{ display: 'flex', gap: 6 }}>
            <button onClick={play} disabled={playing} style={{ background: theme.colors.primary, color: '#fff', border: 'none', borderRadius: 6, padding: '5px 12px', fontSize: 12, fontFamily: theme.font, cursor: 'pointer', opacity: playing ? 0.5 : 1 }}>Play</button>
            <button onClick={reset} style={{ background: theme.colors.surfaceAlt, color: theme.colors.textSecondary, border: '1px solid ' + theme.colors.border, borderRadius: 6, padding: '5px 10px', fontSize: 12, fontFamily: theme.font, cursor: 'pointer' }}>Reset</button>
          </div>
        </div>

        {/* Step indicator */}
        <div style={{ display: 'flex', gap: 4, marginBottom: 10 }}>
          {stepLabels.map((label, i) => (
            <button key={i} onClick={() => { setStep(i); setPlaying(false); }} style={{
              flex: 1, padding: '5px 4px', borderRadius: 6, fontSize: 10, fontFamily: theme.font, cursor: 'pointer',
              background: step === i ? stepColors[i] + '22' : theme.colors.surface,
              border: step === i ? '1px solid ' + stepColors[i] : '1px solid ' + theme.colors.border,
              color: step === i ? stepColors[i] : theme.colors.textSecondary,
              fontWeight: step === i ? 600 : 400,
              transition: 'all 0.3s ease',
            }}>{label}</button>
          ))}
        </div>

        {/* SVG Number Line */}
        <div style={{ background: theme.colors.surface, borderRadius: 10, padding: '8px 4px 4px', marginBottom: 10, border: '1px solid ' + theme.colors.border }}>
          <svg width="100%" viewBox={`0 0 ${SVG_W} ${SVG_H}`} style={{ display: 'block' }}>
            {/* Zone backgrounds */}
            <rect x={PAD_L} y={LINE_Y - 22} width={zoneUnderX - PAD_L} height={44} rx={4} fill={theme.colors.red + '15'} />
            <rect x={zoneUnderX} y={LINE_Y - 22} width={zoneSubX - zoneUnderX} height={44} rx={0} fill={theme.colors.yellow + '10'} />
            <rect x={zoneSubX} y={LINE_Y - 22} width={zoneOverX - zoneSubX} height={44} rx={0} fill={theme.colors.green + '10'} />
            <rect x={zoneOverX} y={LINE_Y - 22} width={PAD_L + CHART_W - zoneOverX} height={44} rx={4} fill={theme.colors.red + '15'} />

            {/* Zone labels */}
            <text x={(PAD_L + zoneUnderX) / 2} y={LINE_Y - 27} textAnchor="middle" fontSize={9} fill={theme.colors.red} fontFamily={theme.font}>UNDERFLOW</text>
            <text x={(zoneUnderX + zoneSubX) / 2} y={LINE_Y - 27} textAnchor="middle" fontSize={8} fill={theme.colors.yellow} fontFamily={theme.font}>subnormal</text>
            <text x={(zoneSubX + zoneOverX) / 2} y={LINE_Y - 27} textAnchor="middle" fontSize={9} fill={theme.colors.green} fontFamily={theme.font}>SAFE fp16 RANGE</text>
            <text x={(zoneOverX + PAD_L + CHART_W) / 2} y={LINE_Y - 27} textAnchor="middle" fontSize={9} fill={theme.colors.red} fontFamily={theme.font}>OVERFLOW</text>

            {/* Main line */}
            <line x1={PAD_L} y1={LINE_Y} x2={PAD_L + CHART_W} y2={LINE_Y} stroke={theme.colors.border} strokeWidth={2} />

            {/* Zone boundary markers */}
            {[FP16_MIN_SUB, FP16_MIN_NORM, FP16_MAX].map((v, i) => {
              const x = toX(Math.log10(v));
              return (
                <g key={i}>
                  <line x1={x} y1={LINE_Y - 20} x2={x} y2={LINE_Y + 20} stroke={theme.colors.textMuted} strokeWidth={1} strokeDasharray="3,3" />
                  <text x={x} y={LINE_Y + 32} textAnchor="middle" fontSize={8} fill={theme.colors.textMuted} fontFamily={theme.font}>
                    {v >= 1 ? v.toFixed(0) : v.toExponential(0)}
                  </text>
                </g>
              );
            })}

            {/* Tick marks */}
            {Array.from({ length: LOG_MAX - LOG_MIN + 1 }, (_, i) => LOG_MIN + i).map(exp => {
              const x = toX(exp);
              return <line key={exp} x1={x} y1={LINE_Y - 3} x2={x} y2={LINE_Y + 3} stroke={theme.colors.textMuted} strokeWidth={1} />;
            })}

            {/* Gradient dots */}
            {pipeline.map((p, i) => {
              const absVal = step === 0 ? Math.abs(p.original) : step === 1 ? Math.abs(p.scaled) : step === 2 ? (isFinite(p.fp16Val) ? Math.abs(p.fp16Val) : 1e6) : (Math.abs(p.unscaled) || 1e-10);
              const logVal = absVal > 0 ? Math.log10(absVal) : LOG_MIN;
              const clampedLog = Math.max(LOG_MIN, Math.min(LOG_MAX, logVal));
              const x = toX(clampedLog);
              const isLost = (step >= 2 && (p.finalStatus === 'overflow' || p.finalStatus === 'underflow'));
              const dotColor = isLost ? theme.colors.red : p.color;
              const isHov = hovered === i;
              const yOff = i % 2 === 0 ? -10 : 10;

              const displayVal = step === 0 ? p.original : step === 1 ? p.scaled : step === 2 ? p.fp16Val : p.unscaled;

              return (
                <g key={i} onMouseEnter={() => setHovered(i)} onMouseLeave={() => setHovered(null)} style={{ cursor: 'pointer' }}>
                  <circle cx={x} cy={LINE_Y + yOff} r={isHov ? 9 : 7} fill={dotColor + (isLost ? '60' : 'cc')} stroke={isHov ? '#fff' : dotColor} strokeWidth={isHov ? 2 : 1} style={{ transition: 'all 0.4s ease' }} />
                  <text x={x} y={LINE_Y + yOff + 1} textAnchor="middle" fontSize={8} fill="#fff" fontFamily={theme.font} fontWeight={700} style={{ pointerEvents: 'none' }}>{p.label}</text>
                  {isHov && (
                    <g>
                      <rect x={x - 48} y={LINE_Y + yOff - 36} width={96} height={18} rx={4} fill={theme.colors.surfaceAlt} stroke={dotColor} strokeWidth={1} />
                      <text x={x} y={LINE_Y + yOff - 23} textAnchor="middle" fontSize={9} fill={dotColor} fontFamily={theme.font} fontWeight={600}>
                        {isFinite(displayVal) ? formatNum(displayVal) : (displayVal > 0 ? '+Inf' : '-Inf')}
                        {isLost ? ' !' : ''}
                      </text>
                    </g>
                  )}
                </g>
              );
            })}
          </svg>
        </div>

        {/* Gradient detail rows */}
        <div style={{ background: theme.colors.surface, borderRadius: 10, padding: '8px 10px', marginBottom: 10, border: '1px solid ' + theme.colors.border }}>
          <div style={{ display: 'flex', gap: 4, marginBottom: 6 }}>
            <div style={{ width: 28, fontSize: 8, color: theme.colors.textMuted }}></div>
            <div style={{ flex: 1, fontSize: 9, color: theme.colors.textSecondary, textAlign: 'center', fontWeight: step === 0 ? 700 : 400, color: step === 0 ? theme.colors.blue : theme.colors.textMuted }}>Original</div>
            <div style={{ width: 14, fontSize: 9, color: theme.colors.textMuted, textAlign: 'center' }}></div>
            <div style={{ flex: 1, fontSize: 9, textAlign: 'center', fontWeight: step === 1 ? 700 : 400, color: step === 1 ? theme.colors.yellow : theme.colors.textMuted }}>x{lossScale}</div>
            <div style={{ width: 14, fontSize: 9, color: theme.colors.textMuted, textAlign: 'center' }}></div>
            <div style={{ flex: 1, fontSize: 9, textAlign: 'center', fontWeight: step === 2 ? 700 : 400, color: step === 2 ? theme.colors.pink : theme.colors.textMuted }}>fp16</div>
            <div style={{ width: 14, fontSize: 9, color: theme.colors.textMuted, textAlign: 'center' }}></div>
            <div style={{ flex: 1, fontSize: 9, textAlign: 'center', fontWeight: step === 3 ? 700 : 400, color: step === 3 ? theme.colors.green : theme.colors.textMuted }}>Result</div>
            <div style={{ width: 52 }}></div>
          </div>
          {pipeline.map((p, i) => {
            const isActive = hovered === i;
            const stc = statusColor(p.finalStatus);
            return (
              <div key={i} onMouseEnter={() => setHovered(i)} onMouseLeave={() => setHovered(null)} style={{
                display: 'flex', alignItems: 'center', gap: 4, padding: '4px 2px', borderRadius: 6,
                background: isActive ? theme.colors.surfaceAlt : 'transparent',
                transition: 'all 0.2s ease', cursor: 'pointer',
              }}>
                <div style={{ width: 28, height: 16, borderRadius: 8, background: p.color + '33', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <span style={{ fontSize: 9, color: p.color, fontWeight: 700 }}>{p.label}</span>
                </div>
                <div style={{ flex: 1, textAlign: 'center', fontSize: 10, color: step >= 0 ? theme.colors.text : theme.colors.textMuted, fontWeight: step === 0 ? 600 : 400, transition: 'all 0.3s' }}>
                  {formatNum(p.original)}
                </div>
                <div style={{ width: 14, textAlign: 'center', fontSize: 9, color: theme.colors.textMuted }}>-></div>
                <div style={{ flex: 1, textAlign: 'center', fontSize: 10, color: step >= 1 ? theme.colors.text : theme.colors.textMuted, fontWeight: step === 1 ? 600 : 400, transition: 'all 0.3s' }}>
                  {formatNum(p.scaled)}
                </div>
                <div style={{ width: 14, textAlign: 'center', fontSize: 9, color: theme.colors.textMuted }}>-></div>
                <div style={{ flex: 1, textAlign: 'center', fontSize: 10, transition: 'all 0.3s', fontWeight: step === 2 ? 600 : 400, color: step >= 2 ? (p.fp16Status === 'overflow' || p.fp16Status === 'underflow' ? theme.colors.red : theme.colors.text) : theme.colors.textMuted }}>
                  {p.fp16Status === 'overflow' ? (p.fp16Val > 0 ? '+Inf' : '-Inf') : p.fp16Status === 'underflow' ? '0' : formatNum(p.fp16Val)}
                </div>
                <div style={{ width: 14, textAlign: 'center', fontSize: 9, color: theme.colors.textMuted }}>-></div>
                <div style={{ flex: 1, textAlign: 'center', fontSize: 10, transition: 'all 0.3s', fontWeight: step === 3 ? 600 : 400, color: step >= 3 ? (p.finalStatus === 'ok' ? theme.colors.green : p.finalStatus === 'imprecise' ? theme.colors.yellow : theme.colors.red) : theme.colors.textMuted }}>
                  {formatNum(p.unscaled)}
                </div>
                <div style={{ width: 52, textAlign: 'right' }}>
                  <span style={{ fontSize: 8, padding: '2px 5px', borderRadius: 4, background: stc + '20', color: stc, fontWeight: 600 }}>
                    {statusLabel(p.finalStatus)}
                  </span>
                </div>
              </div>
            );
          })}
        </div>

        {/* Loss Scale Slider */}
        <div style={{ background: theme.colors.surface, borderRadius: 10, padding: '10px 14px', marginBottom: 10, border: '1px solid ' + theme.colors.border }}>
          <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: 6 }}>
            <span style={{ fontSize: 11, color: theme.colors.textSecondary }}>Loss Scale Factor</span>
            <span style={{ fontSize: 14, fontWeight: 700, color: theme.colors.primary }}>{lossScale.toLocaleString()}x</span>
          </div>
          <input type="range" min={0} max={SCALE_STOPS.length - 1} step={1} value={scaleIdx} onChange={e => setScaleIdx(parseInt(e.target.value))}
            style={{ width: '100%', accentColor: theme.colors.primary, cursor: 'pointer' }} />
          <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 9, color: theme.colors.textMuted, marginTop: 2 }}>
            <span>1x (no scaling)</span>
            <span>65536x</span>
          </div>
          <div style={{ display: 'flex', gap: 5, marginTop: 8 }}>
            {[{ label: 'No Scale', idx: 0 }, { label: 'Low (32x)', idx: 5 }, { label: 'Medium (1024x)', idx: 10 }, { label: 'High (65536x)', idx: 16 }].map(p => (
              <button key={p.idx} onClick={() => { setScaleIdx(p.idx); setStep(3); }} style={{
                flex: 1, padding: '4px 2px', borderRadius: 5, fontSize: 9, fontFamily: theme.font, cursor: 'pointer',
                background: scaleIdx === p.idx ? theme.colors.primary + '22' : theme.colors.surfaceAlt,
                border: scaleIdx === p.idx ? '1px solid ' + theme.colors.primary : '1px solid ' + theme.colors.border,
                color: scaleIdx === p.idx ? theme.colors.primary : theme.colors.textSecondary,
              }}>{p.label}</button>
            ))}
          </div>
        </div>

        {/* Score bar */}
        <div style={{ display: 'flex', gap: 8, marginBottom: 10 }}>
          <div style={{ flex: 1, background: theme.colors.surface, borderRadius: 8, padding: '8px 12px', border: '1px solid ' + theme.colors.border, textAlign: 'center' }}>
            <div style={{ fontSize: 20, fontWeight: 700, color: lostCount === 0 ? theme.colors.green : lostCount < 3 ? theme.colors.yellow : theme.colors.red, transition: 'color 0.3s' }}>{savedCount}/4</div>
            <div style={{ fontSize: 9, color: theme.colors.textSecondary }}>gradients saved</div>
          </div>
          <div style={{ flex: 1, background: theme.colors.surface, borderRadius: 8, padding: '8px 12px', border: '1px solid ' + theme.colors.border, textAlign: 'center' }}>
            <div style={{ fontSize: 20, fontWeight: 700, color: noScaleLost > 0 ? theme.colors.red : theme.colors.green }}>{noScaleLost}/4</div>
            <div style={{ fontSize: 9, color: theme.colors.textSecondary }}>lost without scaling</div>
          </div>
          <div style={{ flex: 1, background: theme.colors.surface, borderRadius: 8, padding: '8px 12px', border: '1px solid ' + theme.colors.border, textAlign: 'center' }}>
            <div style={{ fontSize: 20, fontWeight: 700, color: theme.colors.textSecondary }}>{lossScale > 1 ? (Math.log2(lossScale)).toFixed(0) + ' bits' : '--'}</div>
            <div style={{ fontSize: 9, color: theme.colors.textSecondary }}>range boost</div>
          </div>
        </div>

        {/* Insight */}
        <div style={{
          background: theme.colors.surfaceAlt, borderRadius: 8, padding: '10px 14px',
          fontSize: 11, color: theme.colors.textSecondary, lineHeight: 1.5,
          borderLeft: '3px solid ' + (lostCount > 0 ? theme.colors.red : theme.colors.green),
          transition: 'border-color 0.3s',
        }}>
          <span style={{ color: lostCount > 0 ? theme.colors.red : theme.colors.green, fontWeight: 600 }}>
            {lostCount > 0 ? 'Warning: ' : 'All safe! '}
          </span>
          {lossScale === 1 && 'No loss scaling! Gradient g1 (3e-8) is below fp16 min subnormal (6e-8) and underflows to zero. This tiny gradient carries real learning signal but is permanently lost. Increase the scale to rescue it.'}
          {lossScale > 1 && lossScale <= 8 && 'Scale is too low. g1 is still in the underflow zone. fp16 can only represent values above ~6e-8. You need to multiply g1 above that threshold. Try scale >= 32.'}
          {lossScale >= 16 && lossScale <= 64 && lostCount > 0 && 'Getting closer! g1*' + lossScale + ' = ' + formatNum(3e-8 * lossScale) + ' which is ' + (3e-8 * lossScale < FP16_MIN_SUB ? 'still below' : 'above') + ' the fp16 threshold. Keep increasing to bring all gradients into the safe zone.'}
          {lossScale >= 16 && lostCount === 0 && lossScale < 2048 && 'All gradients survive! The scale ' + lossScale + 'x multiplies g1 to ' + formatNum(3e-8 * lossScale) + ', safely above fp16 min. After fp16 storage, we divide back by ' + lossScale + ' in fp32 to recover the original value. This is the sweet spot!'}
          {lossScale >= 2048 && lostCount === 0 && 'Scale ' + lossScale + 'x works but is getting high. g4 (-45) becomes ' + formatNum(-45 * lossScale) + ' after scaling. fp16 max is 65504. If any gradient exceeds that, it overflows to Inf and gets zeroed out. Try increasing further to see it break.'}
          {lossScale >= 2048 && lostCount > 0 && 'Too much scaling! g4*' + lossScale + ' = ' + formatNum(-45 * lossScale) + ' which exceeds fp16 max (65504) and overflows to Inf. The backward pass detects this and zeros the gradient. This is the loss scaling tradeoff: too little loses small grads, too much overflows large ones.'}
        </div>
      </div>
    </div>
  );
}

